  // Initialize or reset manual chat when language or documents change
  useEffect(() => {
    if (isManualDraft) {
      manualChatRef.current = startManualDraftChat(caseParts, draftLanguage);
    }
  }, [draftLanguage, isManualDraft, caseParts]);

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => {
        const base64String = (reader.result as string).split(',')[1];
        resolve(base64String);
      };
      reader.onerror = (error) => reject(error);
    });
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.size > MAX_FILE_SIZE) {
      setError("File is too large. Please upload a file smaller than 20MB.");
      return;
    }

    setError(null);
    setIsLoading(true);

    try {
      const base64 = await fileToBase64(file);
      let mimeType = file.type;

      if (!mimeType) {
        if (file.name.endsWith('.txt')) mimeType = 'text/plain';
        else if (file.name.endsWith('.pdf')) mimeType = 'application/pdf';
      }

      const parts: MultimodalPart[] = [];
      if (mimeType === 'text/plain') {
        const text = await file.text();
        parts.push({ text });
      } else {
        parts.push({
          inlineData: { mimeType, data: base64 }
        });
      }

      setCaseParts(parts);

      setLoadingStep("Analyzing primary case documents...");
      const analysis = await analyzeCaseFile(parts);

      setLoadingStep("Conducting deep legal research & finding citations...");
      const citations = await researchLegalPrecedents(analysis.summary, analysis.legalIssues);
      analysis.citations = citations;

      setLoadingStep("Drafting legal strategy...");
      const strategy = await generateStrategy(parts);

      setLoadingStep("Preparing hearing materials...");
      const hearingPrep = await prepareHearing(parts);

      setCaseData({
        fileName: file.name,
        fileContent: mimeType === 'text/plain' ? await file.text() : `[Multimodal: ${file.name}]`,
        analysis,
        strategy,
        hearingPrep
      });
      setActiveTab(AppTab.Analysis);
    } catch (err: any) {
      console.error("Error processing file:", err);
      setError("Failed to process file. Gemini AI might be busy or the file format is unsupported.");
    } finally {
      setIsLoading(false);
      setLoadingStep('');
    }
  };

  const cleanDraftText = (text: string) => {
    // If it's a guide, keep some markdown for readability but strip heavy formatting for formal drafts
    // We only strip markdown if it looks like a formal draft (no lists/steps)
    if (text.includes('Step') || text.includes('Guide') || text.includes('Steps to')) {
       return text.replace(/\*\*\*/g, '').replace(/\*\*/g, '').replace(/___/g, '').replace(/__/g, '').replace(/`/g, '').trim();
    }

    return text
      .replace(/\*\*\*/g, '')
      .replace(/\*\*/g, '')
      .replace(/\*/g, '')
      .replace(/___/g, '')
      .replace(/__/g, '')
      .replace(/#/g, '')
      .replace(/`/g, '')
      .trim();
  };

  const handleGenerateDraft = async (type: string) => {
    if (caseParts.length === 0) return;
    setIsDrafting(true);
    setGeneratedDraft(null);
    setError(null);
    try {
      const draft = await generateDraft(caseParts, selectedDomain, type, draftLanguage);
      setGeneratedDraft(cleanDraftText(draft));
    } catch (error) {
      console.error("Drafting error:", error);
      setError("Failed to generate legal draft. The context might be too complex.");
    } finally {
      setIsDrafting(false);
    }
  };

  const handleGenerateManualDraft = async () => {
    if (!manualInput.trim()) {
      setError("Please enter some details for the manual draft.");
      return;
    }

    setIsDrafting(true);
    setError(null);

    try {
      if (!manualChatRef.current) {
        manualChatRef.current = startManualDraftChat(caseParts, draftLanguage);
      }

      const stream = await manualChatRef.current.sendMessageStream({ message: manualInput });
      setManualInput(''); // Clear input for next prompt

      let fullResponse = "";
      setGeneratedDraft(""); // Reset preview for streaming

      for await (const chunk of stream) {
        fullResponse += chunk.text;
        setGeneratedDraft(cleanDraftText(fullResponse));
      }
    } catch (error) {
      console.error("Manual drafting error:", error);
      setError("Failed to generate custom draft. Try refining your instructions.");
    } finally {
      setIsDrafting(false);
    }
  };

  const resetManualChat = () => {
    manualChatRef.current = startManualDraftChat(caseParts, draftLanguage);
    setGeneratedDraft(null);
    setManualInput('');
  };

  const toggleVoiceAssistant = async () => {
    if (isVoiceActive) {
      stopVoiceAssistant();
      return;
    }

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      await navigator.mediaDevices.getUserMedia({ audio: true });

      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      const analysisContext = caseData?.analysis ? `
        CASE SUMMARY: ${caseData.analysis.summary}
        PARTIES: ${caseData.analysis.parties.join(', ')}
        LEGAL ISSUES: ${caseData.analysis.legalIssues.join(', ')}
        RELIEF SOUGHT: ${caseData.analysis.reliefSought}
        CITATIONS FOUND: ${caseData.analysis.citations?.map(c => c.title).join('; ')}
      ` : "No specific analysis available yet. The user might ask to analyze the cause generally.";

      const systemInstruction = `
        You are "Advocate Assistant Pro", a highly skilled legal voice assistant. 
        Your goal is to "samjhain" (understand) the "cause" (the legal case) and discuss it with the Advocate.
        Answer questions "achay se" (thoroughly and professionally).
        CONTEXT: ${analysisContext}
        BEHAVIOR:
        1. Speak professionally in English and Urdu.
        2. Help brainstorm counter-arguments.
        3. Explain complex legal nuances of the current case files.
        4. If asked about legal precedents, refer to the citations we found.
        5. Be a supporting colleague to the advocate, helping them win the case.
      `;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setIsVoiceActive(true);
            const stream = navigator.mediaDevices.getUserMedia({ audio: true }).then(s => {
              const source = inputCtx.createMediaStreamSource(s);
              const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);
              scriptProcessor.onaudioprocess = (e) => {
                const inputData = e.inputBuffer.getChannelData(0);
                const l = inputData.length;
                const int16 = new Int16Array(l);
                for (let i = 0; i < l; i++) int16[i] = inputData[i] * 32768;
                sessionPromise.then(session => {
                  session.sendRealtimeInput({ media: { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' } });
                });
              };
              source.connect(scriptProcessor);
              scriptProcessor.connect(inputCtx.destination);
            });
          },
          onmessage: async (message) => {
            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData) {
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
              const buffer = await decodeAudioData(decode(audioData), outputCtx, 24000, 1);
              const source = outputCtx.createBufferSource();
              source.buffer = buffer;
              source.connect(outputCtx.destination);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
            }
          },
          onclose: () => setIsVoiceActive(false),
          onerror: () => setIsVoiceActive(false),
        },
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction,
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } }
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error("Voice error:", err);
      setIsVoiceActive(false);
    }
  };

  const stopVoiceAssistant = () => {
    if (sessionRef.current) {
      sessionRef.current.close?.();
      sessionRef.current = null;
    }
    setIsVoiceActive(false);
    sourcesRef.current.forEach(s => s.stop());
    sourcesRef.current.clear();
    nextStartTimeRef.current = 0;
  };

  return (
    <div className="flex h-screen overflow-hidden">
      {/* Sidebar */}
      <aside className="w-64 bg-slate-900 text-white flex flex-col shrink-0">
        <div className="p-6 border-b border-slate-800">
          <h1 className="text-xl font-serif font-bold tracking-tight text-amber-400">Advocate AI</h1>
          <p className="text-xs text-slate-400 mt-1 uppercase tracking-widest font-medium">Assistant Pro</p>
        </div>

        <nav className="flex-1 p-4 space-y-2 overflow-y-auto">
          <NavItem icon={<FileUp size={20} />} label="Upload Case" active={activeTab === AppTab.Upload} onClick={() => setActiveTab(AppTab.Upload)} />
          <NavItem icon={<LayoutDashboard size={20} />} label="Case Analysis" active={activeTab === AppTab.Analysis} disabled={!caseData} onClick={() => setActiveTab(AppTab.Analysis)} />
          <NavItem icon={<ShieldAlert size={20} />} label="Strategy & Risks" active={activeTab === AppTab.Strategy} disabled={!caseData} onClick={() => setActiveTab(AppTab.Strategy)} />
          <NavItem icon={<FileText size={20} />} label="Drafting Tool" active={activeTab === AppTab.Drafts} disabled={!caseData} onClick={() => setActiveTab(AppTab.Drafts)} />
          <NavItem icon={<Gavel size={20} />} label="Hearing Prep" active={activeTab === AppTab.HearingPrep} disabled={!caseData} onClick={() => setActiveTab(AppTab.HearingPrep)} />
        </nav>

        <div className="p-4 bg-slate-800 m-4 rounded-xl shadow-inner border border-slate-700/50">
          <div className="flex items-center gap-3 mb-3">
            <div className={`w-3 h-3 rounded-full ${isVoiceActive ? 'bg-red-500 animate-pulse shadow-[0_0_8px_rgba(239,68,68,0.8)]' : 'bg-slate-500'}`}></div>
            <span className="text-xs font-semibold text-slate-300 uppercase">Interactive Voice</span>
          </div>
          <button 
            onClick={toggleVoiceAssistant}
            disabled={!caseData}
            className={`w-full py-3 rounded-lg flex flex-col items-center justify-center gap-1 transition-all duration-300 font-bold ${
              isVoiceActive ? 'bg-red-500 text-white hover:bg-red-600' : 'bg-amber-500 text-slate-900 disabled:opacity-50 hover:bg-amber-400'
            }`}
          >
            <div className="flex items-center gap-2">
              {isVoiceActive ? <MicOff size={18} /> : <Mic size={18} />}
              <span className="text-sm">{isVoiceActive ? 'Stop Session' : 'Discuss Cause'}</span>
            </div>
            {isVoiceActive && (
              <div className="flex gap-1 mt-1">
                <span className="w-1 h-3 bg-white/40 animate-bounce delay-75"></span>
                <span className="w-1 h-3 bg-white/60 animate-bounce delay-150"></span>
                <span className="w-1 h-3 bg-white/40 animate-bounce delay-300"></span>
              </div>
            )}
          </button>
          <p className="text-[10px] text-slate-500 mt-2 text-center uppercase tracking-tight">Real-time brainstorm assistant</p>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto bg-slate-50 relative">
        <header className="bg-white border-b border-slate-200 px-8 py-4 sticky top-0 z-10 flex justify-between items-center">
          <div className="flex items-center gap-4">
            <h2 className="text-lg font-bold text-slate-800 uppercase tracking-tight text-sm">{activeTab}</h2>
            {caseData && (
              <div className="flex items-center gap-2 bg-slate-100 text-slate-600 px-3 py-1 rounded-full text-xs font-semibold border border-slate-200">
                <FileBadge size={14} className="text-amber-500" /> {caseData.fileName}
              </div>
            )}
          </div>
        </header>

        <div className="p-8 max-w-5xl mx-auto">
          {error && (
            <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-xl flex gap-3 text-red-700 animate-in fade-in duration-300">
              <AlertTriangle className="shrink-0" size={20} />
              <p className="text-sm font-medium flex-1">{error}</p>
              <button onClick={() => setError(null)} className="font-bold">×</button>
            </div>
          )}

          {isLoading && (
            <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-50 flex flex-col items-center justify-center">
              <div className="bg-white p-10 rounded-3xl shadow-2xl flex flex-col items-center max-w-md w-full">
                <Loader2 className="animate-spin text-amber-500 mb-6" size={56} />
                <h3 className="text-xl font-serif font-bold text-slate-800 text-center mb-2">Legal Processing Engine</h3>
                <p className="text-slate-500 text-sm animate-pulse text-center">{loadingStep}</p>
                <div className="mt-8 flex gap-2 w-full px-4">
                   <div className="flex-1 h-1.5 bg-slate-100 rounded-full overflow-hidden">
                      <div className="h-full bg-amber-500 animate-[loading_2s_ease-in-out_infinite]"></div>
                   </div>
                </div>
              </div>
            </div>
          )}

          {activeTab === AppTab.Upload && (
            <div className="space-y-6">
              <div className="bg-white p-12 rounded-3xl border-2 border-dashed border-slate-200 flex flex-col items-center justify-center text-center hover:border-amber-400 transition-all cursor-pointer relative group">
                <input type="file" onChange={handleFileUpload} className="absolute inset-0 opacity-0 cursor-pointer" accept=".txt,.pdf,.jpg,.jpeg,.png" />
                <div className="bg-amber-50 p-6 rounded-full text-amber-500 mb-6 group-hover:scale-110 transition-transform flex gap-3">
                  <FileUp size={32} /> <FileBadge size={32} />
                </div>
                <h3 className="text-2xl font-serif font-bold text-slate-800 mb-2">Upload Legal Case Files</h3>
                <p className="text-slate-500 max-w-md text-sm">Upload Petitions, FIRs, Evidence, or Witness Statements. Our AI understands the "cause" and prepares citations instantly.</p>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mt-8">
                <FeatureCard icon={<BookOpen className="text-purple-500" />} title="Citations & Precedents" desc="Automatically searches for relevant case law with direct web links." />
                <FeatureCard icon={<Scale className="text-amber-600" />} title="Legal Drafting" desc="Native Urdu and English drafting for formal court submissions." />
                <FeatureCard icon={<Mic className="text-blue-500" />} title="Brainstorm AI" desc="Talk to the assistant to analyze weaknesses and discuss the cause." />
              </div>
            </div>
          )}

          {activeTab === AppTab.Analysis && caseData?.analysis && (
            <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-8">
                <h3 className="font-bold text-slate-400 uppercase text-xs tracking-widest mb-4">Case Executive Summary</h3>
                <p className="text-slate-700 leading-relaxed text-xl font-serif italic mb-6">"{caseData.analysis.summary}"</p>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <InfoBox label="Case Type" value={caseData.analysis.caseType} />
                  <InfoBox label="Relief Sought" value={caseData.analysis.reliefSought} />
                </div>
              </div>

              {/* Citations Feature */}
              {caseData.analysis.citations && caseData.analysis.citations.length > 0 && (
                <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-8">
                  <div className="flex items-center gap-2 mb-6">
                    <Link size={20} className="text-blue-500" />
                    <h3 className="font-bold text-slate-800 text-sm uppercase tracking-widest">Relevant Citations & Research</h3>
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {caseData.analysis.citations.map((cite, i) => (
                      <a 
                        key={i} 
                        href={cite.uri} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="p-4 bg-slate-50 border border-slate-100 rounded-xl hover:bg-blue-50 hover:border-blue-200 transition-all group flex flex-col justify-between"
                      >
                        <div>
                          <p className="text-sm font-bold text-slate-800 mb-1 group-hover:text-blue-700">{cite.title}</p>
                          <p className="text-[10px] text-slate-400 break-all mb-3">{cite.uri}</p>
                        </div>
                        <span className="text-[10px] font-black text-blue-500 uppercase tracking-tighter flex items-center gap-1">
                          View Full Document <ChevronRight size={10} />
                        </span>
                      </a>
                    ))}
                  </div>
                </div>
              )}

              <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                <DataList title="Parties Involved" items={caseData.analysis.parties} icon={<User size={18} className="text-blue-500" />} />
                <DataList title="Legal Issues" items={caseData.analysis.legalIssues} icon={<AlertTriangle size={18} className="text-red-500" />} />
              </div>
              <DataList title="Case Facts Timeline" items={caseData.analysis.keyFacts} icon={<CheckCircle2 size={18} className="text-green-500" />} />
            </div>
          )}

          {activeTab === AppTab.Strategy && caseData?.strategy && (
            <div className="space-y-6 animate-in fade-in duration-500">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <StatusCard title="Strengths" items={caseData.strategy.strengths} type="success" />
                <StatusCard title="Risks" items={caseData.strategy.risks} type="warning" />
                <StatusCard title="Missing Evidence" items={caseData.strategy.gaps} type="danger" />
              </div>
              <DataList title="Laws & Precedents" items={caseData.strategy.applicableLaws} icon={<FileSearch size={18} className="text-blue-500" />} />
              <div className="bg-white rounded-3xl border p-8">
                <h3 className="font-bold text-slate-800 mb-6 flex items-center gap-2"><Gavel className="text-amber-500" /> Recommended Argument Strategy</h3>
                <div className="space-y-4">
                  {caseData.strategy.argumentFlow.map((step, i) => (
                    <div key={i} className="flex gap-4">
                       <div className="w-8 h-8 rounded-full bg-amber-100 text-amber-700 flex items-center justify-center font-bold shrink-0">{i+1}</div>
                       <div className="flex-1 p-4 bg-slate-50 border rounded-xl text-slate-800">{step}</div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}

          {activeTab === AppTab.Drafts && (
            <div className="space-y-6 animate-in fade-in duration-500">
              <div className="bg-white rounded-3xl border border-slate-200 p-6 shadow-sm">
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mb-8">
                  <div>
                    <h3 className="font-bold text-slate-800 text-lg mb-1">Legal Drafting Engine</h3>
                    <p className="text-slate-500 text-sm">Select domain or provide manual input for custom drafts.</p>
                  </div>

                  <div className="flex p-1 bg-slate-100 rounded-xl">
                    <button 
                      onClick={() => setDraftLanguage('English')}
                      className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${draftLanguage === 'English' ? 'bg-white shadow text-slate-900' : 'text-slate-500'}`}
                    >
                      English
                    </button>
                    <button 
                      onClick={() => setDraftLanguage('Urdu')}
                      className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${draftLanguage === 'Urdu' ? 'bg-white shadow text-slate-900 font-urdu' : 'text-slate-500 font-urdu'}`}
                    >
                      Urdu (اردو)
                    </button>
                  </div>
                </div>

                <div className="flex gap-4 border-b border-slate-100 mb-6">
                  <button 
                    onClick={() => setIsManualDraft(false)}
                    className={`pb-3 px-4 text-sm font-bold transition-all ${!isManualDraft ? 'border-b-2 border-amber-500 text-slate-900' : 'text-slate-400 hover:text-slate-600'}`}
                  >
                    Domain Templates
                  </button>
                  <button 
                    onClick={() => setIsManualDraft(true)}
                    className={`pb-3 px-4 text-sm font-bold transition-all ${isManualDraft ? 'border-b-2 border-amber-500 text-slate-900' : 'text-slate-400 hover:text-slate-600'}`}
                  >
                    Manual Draft (Custom)
                  </button>
                </div>

                {!isManualDraft ? (
                  <>
                    <div className="flex flex-wrap gap-2 mb-8">
                      {(['Family', 'Criminal', 'Civil', 'General'] as LegalDomain[]).map(domain => (
                        <button 
                          key={domain}
                          onClick={() => setSelectedDomain(domain)}
                          className={`px-6 py-3 rounded-2xl text-sm font-bold border transition-all ${
                            selectedDomain === domain 
                              ? 'bg-slate-900 text-white border-slate-900 shadow-lg' 
                              : 'bg-white text-slate-600 border-slate-200 hover:border-amber-400 hover:text-amber-600'
                          }`}
                        >
                          {domain} Law
                        </button>
                      ))}
                    </div>

                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                      {DOMAIN_TEMPLATES[selectedDomain].map(template => (
                        <button 
                          key={template}
                          onClick={() => handleGenerateDraft(template)}
                          disabled={isDrafting}
                          className="group p-5 bg-slate-50 border border-slate-200 rounded-2xl text-left hover:border-amber-400 hover:bg-amber-50 transition-all flex justify-between items-center disabled:opacity-50"
                        >
                          <span className={`text-sm font-bold text-slate-700 group-hover:text-amber-700 ${draftLanguage === 'Urdu' ? 'font-urdu' : ''}`}>{template}</span>
                          <ChevronRight size={16} className="text-slate-400 group-hover:text-amber-500 shrink-0" />
                        </button>
                      ))}
                    </div>
                  </>
                ) : (
                  <div className="space-y-4">
                    <div className="p-5 bg-slate-50 border border-slate-200 rounded-2xl">
                      <div className="flex justify-between items-center mb-3">
                        <label className="block text-xs font-black uppercase text-slate-400 tracking-widest">Custom Instructions / Questions</label>
                        <button 
                          onClick={resetManualChat}
                          className="text-[10px] font-bold text-slate-400 hover:text-amber-600 flex items-center gap-1 uppercase transition-colors"
                        >
                          <RotateCcw size={12} /> New Session
                        </button>
                      </div>
                      <textarea 
                        className={`w-full h-32 bg-white border border-slate-200 rounded-xl p-4 text-sm text-slate-800 outline-none focus:border-amber-400 transition-all resize-none font-medium ${draftLanguage === 'Urdu' ? 'font-urdu' : ''}`}
                        placeholder={draftLanguage === 'Urdu' ? "جیسے کہ: 'طلاق نامہ کیسے تیار کریں؟' یا 'طلاق نامہ تیار کریں جس میں۔۔۔'" : "e.g., 'how to draft Talaq Divorce' or 'Draft a divorce notice explaining...'"}
                        value={manualInput}
                        onChange={(e) => setManualInput(e.target.value)}
                        dir={draftLanguage === 'Urdu' ? 'rtl' : 'ltr'}
                      />
                      <div className="mt-4 flex justify-end">
                        <button 
                          onClick={handleGenerateManualDraft}
                          disabled={isDrafting || !manualInput.trim()}
                          className="flex items-center gap-2 bg-amber-500 text-slate-900 px-6 py-3 rounded-xl font-bold text-sm hover:bg-amber-600 transition-all shadow-md disabled:opacity-50"
                        >
                          <SendHorizontal size={18} />
                          {generatedDraft ? 'Continue Conversation' : 'Ask or Generate'}
                        </button>
                      </div>
                    </div>
                  </div>
                )}
              </div>

              {(isDrafting || generatedDraft) && (
                <div className="bg-white rounded-3xl shadow-xl border border-slate-200 overflow-hidden">
                  <div className="bg-slate-900 px-8 py-5 flex justify-between items-center">
                    <div className="flex items-center gap-3">
                      <PencilLine className="text-amber-400" size={20} />
                      <h3 className="font-bold text-white uppercase text-sm tracking-widest">Assistant Response / Preview</h3>
                    </div>
                    {generatedDraft && !isDrafting && (
                      <div className="flex gap-2">
                        <button 
                          onClick={() => window.print()}
                          className="bg-slate-800 text-white p-2 rounded-lg hover:bg-slate-700 transition-colors"
                          title="Print Document"
                        >
                          <Printer size={18} />
                        </button>
                        <button 
                          onClick={() => {
                            const blob = new Blob([generatedDraft!], { type: 'text/plain;charset=utf-8' });
                            const url = URL.createObjectURL(blob);
                            const a = document.createElement('a');
                            a.href = url;
                            a.download = `Advocate_Draft_${Date.now()}.txt`;
                            a.click();
                          }} 
                          className="bg-amber-500 text-slate-900 px-4 py-2 rounded-lg font-black text-xs hover:bg-amber-400"
                        >
                          EXPORT TEXT
                        </button>
                      </div>
                    )}
                  </div>
                  <div className="p-8 bg-slate-100 min-h-[600px]">
                    {isDrafting && !generatedDraft ? (
                      <div className="flex flex-col items-center justify-center py-20">
                        <Loader2 className="animate-spin text-amber-500 mb-4" size={40} />
                        <p className="font-bold text-slate-800">Assistant is thinking...</p>
                      </div>
                    ) : (
                      <div className="bg-white shadow-inner rounded-xl p-8 border border-slate-200 max-w-4xl mx-auto min-h-[500px]">
                        <textarea 
                          className={`w-full h-full min-h-[550px] text-slate-800 leading-relaxed outline-none resize-none border-none ${draftLanguage === 'Urdu' ? 'font-urdu text-right' : 'font-serif text-left'}`}
                          value={generatedDraft!}
                          onChange={(e) => setGeneratedDraft(e.target.value)}
                          dir={draftLanguage === 'Urdu' ? 'rtl' : 'ltr'}
                        />
                      </div>
                    )}
                  </div>
                </div>
              )}
            </div>
          )}

          {activeTab === AppTab.HearingPrep && caseData?.hearingPrep && (
            <div className="space-y-6 animate-in fade-in duration-500">
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                <DataList title="Hearing Checklist" items={caseData.hearingPrep.checklist} type="checklist" icon={<CheckCircle2 className="text-green-500" />} />
                <DataList title="Predicted Court Inquiries" items={caseData.hearingPrep.predictedQuestions} icon={<Gavel className="text-amber-600" />} />
              </div>
              <div className="bg-white rounded-3xl border p-8">
                <h3 className="font-bold text-slate-800 mb-8 flex items-center gap-2">
                   <ShieldAlert className="text-red-500" /> Counter-Opposition Strategy
                </h3>
                <div className="space-y-6">
                  {caseData.hearingPrep.opponentArguments.map((arg, i) => (
                    <div key={i} className="grid grid-cols-1 md:grid-cols-2 gap-4 bg-slate-50 p-1 rounded-2xl">
                      <div className="p-5 bg-white border border-red-50 rounded-xl shadow-sm">
                        <span className="text-[10px] font-black text-red-500 uppercase tracking-widest block mb-2">Probable Opposition Line</span>
                        <p className="text-slate-800 text-sm italic font-serif leading-relaxed">"{arg}"</p>
                      </div>
                      <div className="p-5 bg-green-50/40 border border-green-50 rounded-xl">
                        <span className="text-[10px] font-black text-green-600 uppercase tracking-widest block mb-2">Proposed Counter</span>
                        <p className="text-slate-900 text-sm font-bold">{caseData.hearingPrep!.counterPoints[i]}</p>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}
        </div>
      </main>
      <style>{`
        @keyframes loading {
          0% { transform: translateX(-100%); }
          100% { transform: translateX(100%); }
        }
      `}</style>
    </div>
  );
};

const NavItem: React.FC<{ icon: any, label: string, active: boolean, disabled?: boolean, onClick: () => void }> = ({ icon, label, active, disabled, onClick }) => (
  <button onClick={onClick} disabled={disabled} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-300 ${active ? 'bg-amber-500 text-slate-900 font-bold shadow-lg ring-1 ring-amber-400' : 'text-slate-400 hover:bg-slate-800 hover:text-white'} ${disabled ? 'opacity-30 cursor-not-allowed grayscale' : ''}`}>
    {icon} <span className="text-sm tracking-tight">{label}</span>
  </button>
);

const FeatureCard: React.FC<{ icon: any, title: string, desc: string }> = ({ icon, title, desc }) => (
  <div className="bg-white p-6 rounded-2xl border border-slate-200 hover:shadow-lg transition-all">
    <div className="mb-4 bg-slate-50 w-12 h-12 rounded-xl flex items-center justify-center">{icon}</div>
    <h4 className="font-bold text-slate-800 mb-2">{title}</h4>
    <p className="text-xs text-slate-500 leading-relaxed">{desc}</p>
