);

const DataList: React.FC<{ title: string, items: string[], icon?: any, type?: 'default' | 'checklist' }> = ({ title, items, icon, type = 'default' }) => (
  <div className="bg-white rounded-2xl border flex flex-col h-full hover:shadow-md transition-shadow">
    <div className="bg-slate-50 px-6 py-4 border-b flex items-center gap-2">{icon}<h3 className="font-bold text-slate-800 text-xs uppercase tracking-wide">{title}</h3></div>
    <div className="p-6 space-y-4 flex-1">
      {items.map((item, i) => (
        <div key={i} className="flex gap-4 items-start group">
          {type === 'checklist' ? <input type="checkbox" className="mt-1 w-4 h-4 rounded border-slate-300 text-amber-500 focus:ring-amber-500 cursor-pointer" /> : <div className="w-1.5 h-1.5 rounded-full bg-amber-400 mt-2 shrink-0"></div>}
          <p className="text-slate-700 text-sm leading-relaxed">{item}</p>
        </div>
      ))}
